import JSEncrypt from "jsencrypt";

// Should default to backbone vault enabled
export const encrypt = (data: string): string => {
  const pubKey = import.meta.env.VITE_BACKBONE_VAULT_PUBLIC_KEY;

  const encrypter = new JSEncrypt({ default_key_size: "4096" });

  if (!pubKey || pubKey.length === 0) {
    throw Error("public key must not be empty");
  }
  if (!data || data.length === 0) {
    throw Error("data must not be empty");
  }

  encrypter.setPublicKey(pubKey);

  const encryptedData = encrypter.encrypt(data);

  if (encryptedData === false) {
    throw Error("Encryption error: Specified key was not a valid RSA key.");
  }
  return encryptedData;
};

